<?php $heading='Campus Ambassador Program';$subheading='Develop leadership skills while supporting responsible community health awareness.';require __DIR__.'/../public/_hero.php';?><section class="section"><div class="business-grid"><?php foreach($programs as$p):?><article class="business-card"><h2><?=e($p['title'])?></h2><p><?=nl2br(e($p['overview']))?></p><h3>Benefits</h3><p><?=nl2br(e($p['benefits']))?></p><h3>Eligibility</h3><p><?=nl2br(e($p['eligibility']))?></p><p><b>Apply by <?=date('d M Y',strtotime($p['application_deadline']))?></b></p></article><?php endforeach;?></div><?php if($programs):?><form class="form-card wide-form" method="post" action="<?=url('campus-ambassador/apply')?>"><h2>Student application</h2><?=csrf_field()?><label>Program<select name="program_id"><?php foreach($programs as$p):?><option value="<?=$p['id']?>"><?=e($p['title'])?></option><?php endforeach;?></select></label><?php foreach(['full_name'=>'Full name','email'=>'Email','phone'=>'Phone','institution'=>'Institution','student_id'=>'Student ID (optional)','department'=>'Department / subject','study_year'=>'Study year','facebook_url'=>'Facebook profile (optional)']as$n=>$label):?><label><?=$label?><input name="<?=$n?>" value="<?=e($old[$n]??'')?>" <?=str_contains($label,'optional')?'':'required'?>></label><?php if(!empty($errors[$n])):?><small class="field-error"><?=e($errors[$n][0])?></small><?php endif;?><?php endforeach;?><label>Why do you want to join?<textarea name="why_join" required><?=e($old['why_join']??'')?></textarea></label><label>Relevant experience<textarea name="experience"><?=e($old['experience']??'')?></textarea></label><button class="btn">Submit Application</button></form><?php endif;?></section>
